    // Helper function to lookup navaid by ident
    window.MAT.lookupNavaid = function(ident) {
        ident = ident.toUpperCase().trim();
        
        // Direct lookup
        if (window.MAT.navaidsDatabase[ident]) {
            return window.MAT.navaidsDatabase[ident];
        }
        
        // Search by original ident (handles duplicates with suffix)
        for (const key in window.MAT.navaidsDatabase) {
            if (window.MAT.navaidsDatabase[key].ident === ident) {
                return window.MAT.navaidsDatabase[key];
            }
        }
        
        return null;
    };
    
    // Helper to find navaids near a point
    window.MAT.findNearbyNavaids = function(lat, lon, radiusNm, types) {
        const results = [];
        const radiusDeg = radiusNm / 60; // Approximate
        
        for (const key in window.MAT.navaidsDatabase) {
            const nav = window.MAT.navaidsDatabase[key];
            
            // Type filter
            if (types && types.length > 0 && !types.includes(nav.type)) {
                continue;
            }
            
            // Quick bounding box check
            const dLat = Math.abs(nav.lat - lat);
            const dLon = Math.abs(nav.lon - lon);
            if (dLat > radiusDeg || dLon > radiusDeg * 1.5) {
                continue;
            }
            
            // Calculate distance
            const dist = Math.sqrt(dLat * dLat + dLon * dLon * Math.cos(lat * Math.PI / 180) * Math.cos(lat * Math.PI / 180)) * 60;
            if (dist <= radiusNm) {
                results.push({
                    ...nav,
                    distance: Math.round(dist * 10) / 10,
                    key: key
                });
            }
        }
        
        return results.sort((a, b) => a.distance - b.distance);
    };
    
